<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>GONDOLA — System Overview</title>
<style>
  :root {
    --bg-dark: #1e1e1e;
    --bg-darker: #181818;
    --bg-light: #252526;
    --bg-panel: rgba(30,30,30,0.85);
    --text-main: #d4d4d4;
    --text-dim: #a0a0a0;
    --accent: #0e639c;
    --accent-hover: #1177bb;
    --border: #333;
    --cyan: #4fc1ff;
    --green: #4ade80;
    --green-dim: #6a9955;
    --yellow: #d7ba7d;
    --red: #f44747;
    --magenta: #c586c0;
    --blue: #569cd6;
    --orange: #d35400;
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background-color: var(--bg-darker);
    color: var(--text-main);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    line-height: 1.6;
    min-height: 100vh;
  }

  /* ── TOP HEADER ── */
  .site-header {
    background: linear-gradient(180deg, #0d0d0d 0%, var(--bg-darker) 100%);
    border-bottom: 1px solid var(--border);
    padding: 40px 60px 30px;
    position: relative;
    overflow: hidden;
  }
  .site-header::before {
    content: '';
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent 0%, var(--cyan) 30%, var(--accent) 60%, transparent 100%);
    animation: headerPulse 4s ease-in-out infinite;
  }
  @keyframes headerPulse {
    0%, 100% { opacity: 0.4; }
    50% { opacity: 1; }
  }
  .header-eyebrow {
    font-family: 'Consolas', monospace;
    font-size: 11px;
    letter-spacing: 3px;
    color: var(--cyan);
    text-transform: uppercase;
    margin-bottom: 8px;
  }
  .header-title {
    font-size: 48px;
    font-weight: 800;
    color: #fff;
    letter-spacing: -1px;
    line-height: 1;
    margin-bottom: 8px;
  }
  .header-title span { color: var(--cyan); }
  .header-sub {
    font-size: 14px;
    color: var(--text-dim);
    font-family: 'Consolas', monospace;
  }
  .header-badge {
    display: inline-block;
    background: rgba(14,99,156,0.25);
    border: 1px solid var(--accent);
    color: var(--cyan);
    font-size: 11px;
    font-family: 'Consolas', monospace;
    padding: 2px 8px;
    border-radius: 3px;
    margin-left: 12px;
    vertical-align: middle;
  }

  /* ── NAV TOC ── */
  .toc-bar {
    background: rgba(0,0,0,0.4);
    border-bottom: 1px solid var(--border);
    padding: 0 60px;
    display: flex;
    gap: 0;
    overflow-x: auto;
    flex-shrink: 0;
    position: sticky;
    top: 0;
    z-index: 100;
  }
  .toc-bar a {
    display: block;
    padding: 12px 16px;
    font-size: 12px;
    color: var(--text-dim);
    text-decoration: none;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: bold;
    border-bottom: 2px solid transparent;
    white-space: nowrap;
    transition: color 0.2s, border-color 0.2s;
  }
  .toc-bar a:hover {
    color: var(--cyan);
    border-bottom-color: var(--cyan);
  }

  /* ── LAYOUT ── */
  .container {
    max-width: 1300px;
    margin: 0 auto;
    padding: 40px 60px 80px;
  }

  /* ── SECTION ── */
  .section {
    margin-bottom: 60px;
  }
  .section-label {
    font-family: 'Consolas', monospace;
    font-size: 10px;
    letter-spacing: 3px;
    color: var(--cyan);
    text-transform: uppercase;
    margin-bottom: 6px;
  }
  .section-title {
    font-size: 26px;
    font-weight: 700;
    color: #fff;
    margin-bottom: 24px;
    padding-bottom: 12px;
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    gap: 12px;
  }
  .section-title .icon { font-size: 22px; }

  /* ── CARDS GRID ── */
  .card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 16px;
  }
  .card-grid-2 {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(380px, 1fr));
    gap: 16px;
  }

  /* ── CARD ── */
  .card {
    background: var(--bg-light);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 18px 20px;
    position: relative;
    overflow: hidden;
    transition: border-color 0.2s;
  }
  .card:hover { border-color: var(--accent); }
  .card-accent-line {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
  }
  .card-title {
    font-size: 13px;
    font-weight: bold;
    color: #fff;
    margin-bottom: 6px;
    font-family: 'Consolas', monospace;
  }
  .card-desc {
    font-size: 12px;
    color: var(--text-dim);
    line-height: 1.5;
  }
  .card-meta {
    margin-top: 10px;
    font-size: 11px;
    font-family: 'Consolas', monospace;
    color: var(--text-dim);
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
  }
  .tag {
    background: rgba(255,255,255,0.07);
    border: 1px solid var(--border);
    padding: 2px 7px;
    border-radius: 3px;
    font-size: 10px;
    font-family: 'Consolas', monospace;
  }
  .tag.cyan   { color: var(--cyan);    border-color: rgba(79,193,255,0.3); }
  .tag.green  { color: var(--green);   border-color: rgba(74,222,128,0.3); }
  .tag.yellow { color: var(--yellow);  border-color: rgba(215,186,125,0.3); }
  .tag.red    { color: var(--red);     border-color: rgba(244,71,71,0.3); }
  .tag.magenta{ color: var(--magenta); border-color: rgba(197,134,192,0.3); }
  .tag.blue   { color: var(--blue);    border-color: rgba(86,156,214,0.3); }
  .tag.orange { color: var(--orange);  border-color: rgba(211,84,0,0.3); }

  /* ── ARCH DIAGRAM ── */
  .arch-diagram {
    background: #0d0d0d;
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 30px;
    font-family: 'Consolas', 'Monaco', monospace;
    font-size: 12px;
    color: var(--text-main);
    overflow-x: auto;
    line-height: 1.7;
    position: relative;
  }
  .arch-diagram .layer-title {
    color: var(--cyan);
    font-weight: bold;
    letter-spacing: 2px;
    font-size: 10px;
    text-transform: uppercase;
  }
  .arch-diagram .box {
    display: inline-block;
    border: 1px solid;
    padding: 3px 10px;
    border-radius: 3px;
    margin: 2px;
    font-size: 11px;
  }
  .arch-diagram .box-blue   { border-color: var(--blue);    color: var(--blue); }
  .arch-diagram .box-cyan   { border-color: var(--cyan);    color: var(--cyan); }
  .arch-diagram .box-green  { border-color: var(--green);   color: var(--green); }
  .arch-diagram .box-yellow { border-color: var(--yellow);  color: var(--yellow); }
  .arch-diagram .box-red    { border-color: var(--red);     color: var(--red); }
  .arch-diagram .box-magenta{ border-color: var(--magenta); color: var(--magenta); }
  .arch-diagram .arrow { color: var(--text-dim); }

  /* ── FLOW LIST ── */
  .flow-list {
    counter-reset: flow;
    list-style: none;
    display: flex;
    flex-direction: column;
    gap: 0;
  }
  .flow-list li {
    counter-increment: flow;
    display: flex;
    gap: 16px;
    padding: 14px 0;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }
  .flow-list li:last-child { border-bottom: none; }
  .flow-num {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--accent);
    color: #fff;
    font-size: 12px;
    font-weight: bold;
    font-family: 'Consolas', monospace;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .flow-content { flex: 1; }
  .flow-step { font-weight: bold; color: var(--cyan); font-size: 13px; margin-bottom: 3px; font-family: 'Consolas', monospace; }
  .flow-desc { font-size: 13px; color: var(--text-dim); }

  /* ── TOOL TABLE ── */
  .tool-group { margin-bottom: 28px; }
  .tool-group-title {
    font-size: 11px;
    font-family: 'Consolas', monospace;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--cyan);
    margin-bottom: 10px;
    padding-left: 4px;
    border-left: 3px solid var(--accent);
    padding-bottom: 2px;
  }
  .tool-pills {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
  }
  .tool-pill {
    background: rgba(14,99,156,0.12);
    border: 1px solid rgba(14,99,156,0.4);
    color: var(--cyan);
    font-size: 11px;
    font-family: 'Consolas', monospace;
    padding: 3px 9px;
    border-radius: 3px;
    cursor: default;
    transition: background 0.15s;
  }
  .tool-pill:hover { background: rgba(14,99,156,0.28); }
  .tool-pill.write { border-color: rgba(74,222,128,0.4); color: var(--green); background: rgba(74,222,128,0.07); }
  .tool-pill.danger { border-color: rgba(244,71,71,0.4); color: var(--red); background: rgba(244,71,71,0.07); }
  .tool-pill.analysis { border-color: rgba(215,186,125,0.4); color: var(--yellow); background: rgba(215,186,125,0.07); }
  .tool-pill.git { border-color: rgba(197,134,192,0.4); color: var(--magenta); background: rgba(197,134,192,0.07); }
  .tool-pill.web { border-color: rgba(86,156,214,0.4); color: var(--blue); background: rgba(86,156,214,0.07); }
  .tool-pill.test { border-color: rgba(211,84,0,0.4); color: var(--orange); background: rgba(211,84,0,0.07); }

  /* ── MODEL CARDS ── */
  .model-card {
    background: var(--bg-light);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 16px 18px;
    position: relative;
    overflow: hidden;
    transition: border-color 0.2s;
  }
  .model-card:hover { border-color: var(--accent); }
  .model-name { font-size: 14px; font-weight: bold; color: #fff; margin-bottom: 4px; }
  .model-id { font-family: 'Consolas', monospace; font-size: 10px; color: var(--text-dim); margin-bottom: 8px; }
  .model-desc { font-size: 12px; color: var(--text-dim); margin-bottom: 10px; line-height: 1.5; }
  .model-stats { display: flex; flex-wrap: wrap; gap: 8px; font-size: 11px; font-family: 'Consolas', monospace; }
  .model-stat { color: var(--text-dim); }
  .model-stat span { color: var(--cyan); }
  .rank-badge {
    position: absolute;
    top: 14px; right: 14px;
    font-size: 10px;
    font-weight: bold;
    font-family: 'Consolas', monospace;
    padding: 2px 7px;
    border-radius: 3px;
    border: 1px solid;
    text-transform: uppercase;
  }
  .rank-1 { color: var(--green);   border-color: var(--green);   background: rgba(74,222,128,0.1); }
  .rank-2 { color: var(--yellow);  border-color: var(--yellow);  background: rgba(215,186,125,0.1); }
  .rank-3 { color: var(--red);     border-color: var(--red);     background: rgba(244,71,71,0.1); }
  .rank-4 { color: #ef4444;        border-color: #ef4444;        background: rgba(239,68,68,0.1); }

  /* ── RISK METER ── */
  .risk-table { width: 100%; border-collapse: collapse; font-size: 13px; }
  .risk-table th {
    text-align: left;
    padding: 10px 14px;
    font-family: 'Consolas', monospace;
    font-size: 10px;
    letter-spacing: 1px;
    text-transform: uppercase;
    color: var(--text-dim);
    border-bottom: 1px solid var(--border);
    background: rgba(0,0,0,0.3);
  }
  .risk-table td {
    padding: 10px 14px;
    border-bottom: 1px solid rgba(255,255,255,0.05);
    vertical-align: top;
  }
  .risk-table tr:last-child td { border-bottom: none; }
  .risk-table .risk-name { font-family: 'Consolas', monospace; color: var(--cyan); font-size: 12px; }
  .risk-table .risk-score { font-family: 'Consolas', monospace; font-weight: bold; }
  .risk-score.critical { color: var(--red); }
  .risk-score.high     { color: var(--yellow); }
  .risk-score.medium   { color: #fb923c; }
  .risk-score.low      { color: var(--green); }

  /* ── UI SCREENSHOT MOCK ── */
  .ui-mock {
    background: #0d0d0d;
    border: 1px solid var(--border);
    border-radius: 6px;
    overflow: hidden;
    font-family: 'Consolas', monospace;
    font-size: 12px;
  }
  .ui-mock-bar {
    background: rgba(0,0,0,0.6);
    padding: 8px 16px;
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    gap: 12px;
  }
  .ui-mock-dot { width: 10px; height: 10px; border-radius: 50%; }
  .ui-mock-title { color: var(--text-dim); font-size: 11px; margin-left: 6px; }
  .ui-mock-body {
    display: flex;
    height: 320px;
  }
  .ui-mock-sidebar {
    width: 160px;
    border-right: 1px solid var(--border);
    background: rgba(0,0,0,0.2);
    padding: 10px;
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }
  .ui-mock-main {
    flex: 1;
    background: rgba(30,30,30,0.6);
    display: flex;
    flex-direction: column;
  }
  .ui-mock-header {
    height: 36px;
    border-bottom: 1px solid var(--border);
    background: rgba(24,24,24,0.5);
    padding: 0 12px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
  }
  .ui-mock-chat { flex: 1; padding: 12px; overflow: hidden; }
  .ui-mock-msg {
    padding: 6px 10px;
    border-radius: 4px;
    border: 1px solid var(--border);
    background: rgba(0,0,0,0.5);
    margin-bottom: 6px;
    font-size: 10px;
    color: var(--text-dim);
    max-width: 85%;
  }
  .ui-mock-msg.user { margin-left: auto; color: var(--text-main); }
  .ui-mock-msg.tool { color: var(--yellow); border-color: rgba(215,186,125,0.2); font-size: 9px; }
  .ui-mock-input {
    height: 44px;
    border-top: 1px solid var(--border);
    background: rgba(24,24,24,0.6);
    padding: 0 12px;
    display: flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
    position: relative;
  }
  .ui-mock-input-box {
    flex: 1;
    background: rgba(0,0,0,0.6);
    border: 1px solid var(--border);
    border-radius: 4px;
    height: 28px;
    padding: 0 8px;
    font-size: 10px;
    color: var(--text-dim);
    display: flex;
    align-items: center;
    position: relative;
    overflow: hidden;
  }
  /* perimeter chase on mock input */
  .ui-mock-input-box::before {
    content: '';
    position: absolute;
    top: 0; left: -100%; width: 100%; height: 1px;
    background: linear-gradient(90deg, transparent, var(--cyan), transparent);
    animation: mockChaseTop 2s linear infinite;
  }
  @keyframes mockChaseTop {
    0% { left: -100%; }
    100% { left: 100%; }
  }
  .ui-mock-avatar-col {
    width: 130px;
    border-left: 1px solid var(--border);
    background: rgba(0,0,0,0.2);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 14px 10px;
    flex-shrink: 0;
    gap: 8px;
  }
  .avatar-mock {
    width: 70px;
    height: 70px;
    border-radius: 4px;
    background: linear-gradient(135deg, #1a2a3a 0%, #0d1a2a 100%);
    border: 1px solid var(--accent);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 28px;
    position: relative;
    overflow: hidden;
  }
  .avatar-mock::after {
    content: '';
    position: absolute;
    bottom: 0; left: 0; right: 0; height: 2px;
    background: linear-gradient(90deg, transparent, var(--cyan), transparent);
    animation: avatarPulse 2s ease-in-out infinite;
  }
  @keyframes avatarPulse {
    0%, 100% { opacity: 0.2; }
    50% { opacity: 1; }
  }
  .avatar-status-mock { font-size: 9px; color: var(--green); }
  .pulse-mock { width: 100%; }
  .pulse-bar-bg { height: 3px; background: #222; border-radius: 2px; overflow: hidden; margin-top: 4px; }
  .pulse-bar-fill { height: 100%; background: var(--green); width: 35%; transition: width 1s; }
  .pulse-label { font-size: 9px; color: var(--text-dim); margin-top: 3px; }

  .sidebar-section-label { font-size: 9px; color: var(--text-dim); text-transform: uppercase; letter-spacing: 1px; }
  .mock-stat { font-size: 9px; display: flex; justify-content: space-between; padding: 2px 0; }
  .mock-stat span { color: var(--cyan); }

  /* ── INFO BOX ── */
  .info-box {
    background: rgba(14,99,156,0.1);
    border: 1px solid rgba(14,99,156,0.4);
    border-left: 3px solid var(--accent);
    border-radius: 4px;
    padding: 14px 18px;
    margin-bottom: 20px;
    font-size: 13px;
    color: var(--text-dim);
  }
  .info-box strong { color: var(--cyan); }

  /* ── WARNING BOX ── */
  .warn-box {
    background: rgba(244,71,71,0.07);
    border: 1px solid rgba(244,71,71,0.3);
    border-left: 3px solid var(--red);
    border-radius: 4px;
    padding: 14px 18px;
    margin-bottom: 20px;
    font-size: 13px;
    color: var(--text-dim);
  }
  .warn-box strong { color: var(--red); }

  /* ── PERSISTENCE DIAGRAM ── */
  .git-diagram {
    background: #0d0d0d;
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 24px;
    font-family: 'Consolas', monospace;
    font-size: 12px;
    line-height: 1.9;
    color: var(--text-dim);
    overflow-x: auto;
  }
  .git-branch { color: var(--green); font-weight: bold; }
  .git-shadow { color: var(--magenta); font-weight: bold; }
  .git-commit { color: var(--yellow); }
  .git-msg { color: var(--text-dim); font-style: italic; }

  /* ── RULES ── */
  .rule-list { list-style: none; display: flex; flex-direction: column; gap: 10px; }
  .rule-list li {
    display: flex;
    gap: 12px;
    align-items: flex-start;
    padding: 12px 14px;
    background: var(--bg-light);
    border: 1px solid var(--border);
    border-radius: 5px;
    font-size: 13px;
  }
  .rule-icon { font-size: 16px; flex-shrink: 0; }
  .rule-text { color: var(--text-main); }
  .rule-text strong { color: var(--cyan); }

  /* ── FOOTER ── */
  .site-footer {
    background: #0d0d0d;
    border-top: 1px solid var(--border);
    padding: 24px 60px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 12px;
    color: var(--text-dim);
    font-family: 'Consolas', monospace;
  }
  .site-footer span { color: var(--cyan); }

  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 6px; height: 6px; }
  ::-webkit-scrollbar-track { background: var(--bg-darker); }
  ::-webkit-scrollbar-thumb { background: #444; border-radius: 3px; }
  ::-webkit-scrollbar-thumb:hover { background: #666; }

  /* ── RESPONSIVE ── */
  @media (max-width: 900px) {
    .site-header, .container, .toc-bar, .site-footer { padding-left: 20px; padding-right: 20px; }
    .header-title { font-size: 32px; }
    .card-grid, .card-grid-2 { grid-template-columns: 1fr; }
    .ui-mock-body { height: auto; flex-direction: column; }
    .ui-mock-avatar-col { width: 100%; border-left: none; border-top: 1px solid var(--border); flex-direction: row; }
  }
</style>
</head>
<body>

