  // Animate pulse bar on load
  setTimeout(() => {
    const fill = document.querySelector('.pulse-bar-fill');
    if (fill) fill.style.width = '35%';
  }, 500);

  // Smooth scroll for TOC links
  document.querySelectorAll('.toc-bar a').forEach(link => {
    link.addEventListener('click', e => {
      e.preventDefault();
      const id = link.getAttribute('href').slice(1);
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    });
  });

  // Highlight active TOC link on scroll
  const sections = document.querySelectorAll('.section[id]');
  const tocLinks = document.querySelectorAll('.toc-bar a');
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        const id = entry.target.id;
        tocLinks.forEach(l => {
          l.style.color = l.getAttribute('href') === '#'+id ? 'var(--cyan)' : '';
          l.style.borderBottomColor = l.getAttribute('href') === '#'+id ? 'var(--cyan)' : 'transparent';
        });
      }
    });
  }, { rootMargin: '-20% 0px -70% 0px' });
  sections.forEach(s => observer.observe(s));
</script>
</body>
