}

/* ─── Confidence table ───────────────────────────────────── */
.confidence-row { }
.confidence-row td { padding: 0.55rem 1rem; }

.conf-bar-wrap {
  display: flex;
  align-items: center;
  gap: 0.6rem;
}

.conf-bar {
