  border-radius: 2px;
  background: var(--green);
  opacity: 0.85;
}

/* ─── Risk settings ──────────────────────────────────────── */
.risk-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-top: 1.5rem;
}

.risk-card {
