  font-size: 0.75rem;
  color: var(--cyan);
  margin-bottom: 0.3rem;
}

.risk-desc {
  font-size: 0.82rem;
  color: var(--text-dim);
  line-height: 1.6;
}

/* ─── Hold list callout ──────────────────────────────────── */
.hold-callout {
  margin-top: 1.5rem;
  border: 1px solid rgba(248, 81, 73, 0.3);
