  margin-bottom: 0.5rem;
}

.dream-step h4 {
  font-size: 0.88rem;
  font-weight: 600;
  color: var(--text-bright);
  margin-bottom: 0.35rem;
}

.dream-step p {
  font-size: 0.78rem;
  color: var(--text-dim);
  line-height: 1.55;
}

/* ─── UI layout diagram ──────────────────────────────────── */
.ui-diagram {
  display: grid;
  grid-template-columns: 160px 1fr 160px;
  gap: 1rem;
  margin-top: 1.5rem;
  font-size: 0.82rem;
}

.ui-col {
