  padding: 0.4rem 0.8rem;
  font-family: var(--mono);
  font-size: 0.62rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--text-dim);
}

.ui-center-panel-body {
  padding: 0.6rem 0.8rem;
  font-size: 0.78rem;
  color: var(--text-dim);
  line-height: 1.6;
}

/* ─── Premarket scoring ──────────────────────────────────── */
.score-bars {
