  background: rgba(255,255,255,0.06);
  border-radius: 3px;
  overflow: hidden;
}

.score-bar-fill {
  height: 100%;
  border-radius: 3px;
  background: linear-gradient(90deg, var(--blue-bright), var(--cyan));
}

.score-bar-pts {
  font-family: var(--mono);
  font-size: 0.72rem;
  color: var(--cyan);
  text-align: right;
}

/* ─── Code block ─────────────────────────────────────────── */
.code-block {
  background: #010409;
  border: 1px solid var(--border-blue);
  border-radius: var(--radius);
  padding: 1.2rem 1.5rem;
  font-family: var(--mono);
  font-size: 0.8rem;
  line-height: 1.75;
  color: #c9d1d9;
  overflow-x: auto;
  margin-top: 1.5rem;
  box-shadow: inset 0 0 30px rgba(0,0,0,0.3);
}

.code-block .k { color: #ff7b72; } /* keyword */
.code-block .s { color: #a5d6ff; } /* string */
.code-block .n { color: #ffa657; } /* number */
.code-block .c { color: #8b949e; } /* comment */
.code-block .p { color: #c9d1d9; } /* punctuation */
.code-block .key { color: #79c0ff; } /* key */

/* ─── Inline code ────────────────────────────────────────── */
code {
  font-family: var(--mono);
  font-size: 0.8em;
  color: var(--cyan);
  background: rgba(88, 166, 255, 0.07);
  padding: 0.1em 0.4em;
  border-radius: 3px;
  border: 1px solid rgba(88, 166, 255, 0.15);
}

/* ─── Pull quote ─────────────────────────────────────────── */
.pull-quote {
  border-left: 3px solid var(--blue-bright);
  padding: 0.8rem 1.4rem;
  margin: 1.5rem 0;
  font-size: 0.95rem;
  color: var(--text);
  font-style: italic;
  background: rgba(31, 111, 235, 0.05);
  border-radius: 0 var(--radius) var(--radius) 0;
}

/* ─── Footer ─────────────────────────────────────────────── */
footer {
  text-align: center;
  padding: 3rem 2rem;
  border-top: 1px solid var(--border);
  font-family: var(--mono);
