  z-index: 1;
}

footer::before {
  content: '';
  display: block;
  width: 200px;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--border-blue), transparent);
  margin: 0 auto 1.5rem;
}

/* ─── Responsive ─────────────────────────────────────────── */
@media (max-width: 760px) {
  nav { padding: 0 1rem; gap: 1rem; }
  .nav-links { display: none; }
  .container { padding: 0 1.2rem; }
